        this.args = args;
        this.h = new HashBuilder().append(sql).append(args).build();
    }

    @Override
    public int hashCode() {
        return Long.hashCode(h);
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        SqlCacheKey that = (SqlCacheKey) obj;
        return h == that.h && sql.equals(that.sql) && args.equals(that.args);
    }

    @Override
    public String toString() {
        return sql + " | " + args;
    }

    // Comparable implementation for Equatable compatibility (if needed for sorting)
    @Override
    public int compareTo(SqlCacheKey other) {
        int cmp = Long.compare(this.h, other.h);
        if (cmp != 0) return cmp;
        cmp = this.sql.compareTo(other.sql);
        if (cmp != 0) return cmp;
        return this.args.compareTo(other.args);
    }
}

