public class TypedActorSystemImpl implements TypedActorSystem {
    private final String systemName;
    private final CActorRuntime runtime;
    private final long startTimeStamp;
    private final java.util.HashMap<String, String> actorRegistry;
    private final java.util.concurrent.atomic.AtomicBoolean terminated;

    public TypedActorSystemImpl(String name, CActorRuntime runtime) {
        this.systemName = name;
        this.runtime = runtime;
        this.startTimeStamp = java.time.Instant.now().toEpochMilli();
        this.actorRegistry = new java.util.HashMap<>();
        this.terminated = new java.util.concurrent.atomic.AtomicBoolean(false);
    }

    @Override
    public String getName() {
        return systemName;
    }

    /**
     * 创建顶级Actor
     *
     * @param behavior Actor的行为
     * @param name Actor的名称
     * @return Actor的引用
     */
    @Override
    public <U> TypedActorRef<U> createActor(TypedBehavior<U> behavior, String name) {
        if (terminated.get()) {
            throw new RuntimeException("Actor system is terminated");
        }

        // 创建类型安全的Actor包装器
        TypedActorWrapper<U> typedActor = new TypedActorWrapper<>(behavior, this);

        // 使用现有的运行时创建Actor
        SimpleActorFactory<Actor> factory = new SimpleActorFactory<>(() -> typedActor);
        Props<Actor> props = new Props<>(factory);
        ActorRef actorRef = runtime.actorOf(props, name);

        // 创建类型安全的ActorRef包装器
        TypedActorRefImpl<U> typedActorRef = new TypedActorRefImpl<>(actorRef, name);

        // 注册到注册表
        actorRegistry.put(name, name);

        return typedActorRef;
    }

    @Override
    public boolean terminate() {
        if (terminated.compareAndSet(false, true)) {
            // 清空注册表
            actorRegistry.clear();

            // 终止底层运行时
            runtime.shutdown();
            return true;
        }
        return false;
    }

    @Override
    public boolean isTerminated() {
        return terminated.get();
    }

    @Override
    public long startTime() {
        return startTimeStamp;
    }

    /**
     * 创建Actor
     */
    @Override
    public TypedActorRef<Object> createActor(TypedBehavior<Object> behavior, String name) {
        // 通过泛型版本创建真实的类型安全Actor
        return createActor(behavior, name);
    }

    /**
     * Actor选择 - 根据路径查找Actor
     * 实现与标准ActorSystem兼容的API
     */
    @Override
    public TypedActorSelection<Object> actorSelection(String path) {
        return new TypedActorSelectionImpl(path, this);
    }

    /**
     * 查找Actor
     */
    @Override
    public <U> java.util.Optional<TypedActorRef<U>> findActor(String name) {
        // 简化实现，暂时返回 empty
        return java.util.Optional.empty();
    }

    /**
     * 获取所有Actor名称
     */
    @Override
    public java.util.List<String> getAllActorNames() {
        // 简化实现，返回空列表
        return java.util.Collections.emptyList();
    }
}

