/**
 * Updates the parser's buffer to ensure at least 'length' bytes are available for reading.
 *
 * @param parser the parser instance to update
 * @param length the minimum number of bytes required in the buffer
 * @return true if the buffer was successfully updated to contain at least 'length' bytes, false otherwise
 */
public static boolean parserUpdateBuffer(ParserT parser, long length) {
    if (parser.readHandler == null) {
        throw new RuntimeException("read handler must be set");
    }

    if (parser.unread >= length) {
        return true;
    }

    if (parser.encoding == EncodingT_ANY_ENCODING && !parserDetermineEncoding(parser)) {
        return false;
    }

    long bufferLen = parser.buffer.size();
    if (parser.bufferPos > 0 && parser.bufferPos < bufferLen) {
        // Copy remaining data from bufferPos to end into bufferTemp
        for (long i = parser.bufferPos; i < bufferLen; i++) {
            parser.bufferTemp.set((int)(i - parser.bufferPos), parser.buffer.get((int)i));
        }
        bufferLen -= parser.bufferPos;
        parser.bufferPos = 0;
    } else if (parser.bufferPos == bufferLen) {
        bufferLen = 0;
        parser.bufferPos = 0;
    }

    if (parser.bufferTemp.size() >= inputBufferSize) {
        parser.buffer = parser.bufferTemp;
    } else {
        ArrayList<Byte> tBuffer = new ArrayList<>();
        for (int i = 0; i < parser.buffer.size(); i++) {
            tBuffer.add(parser.buffer.get(i));
        }
        // Fill remaining capacity with zeros
        while (tBuffer.size() < inputBufferSize) {
            tBuffer.add((byte)0);
        }
        parser.buffer = tBuffer;
    }

    boolean first = true;

    while (parser.unread < length) {
        if ((!first || parser.rawBufferPos == parser.rawBuffer.size()) && !parserUpdateRawBuffer(parser)) {
            parser.buffer = new ArrayList<>(parser.buffer.subList(0, (int)bufferLen));
            return false;
        }

        first = false;

        Boolean innerResult = parserUpdateBufferInner(parser, bufferLen);
        if (innerResult != null) {
            return innerResult;
        }

        if (parser.eof) {
            parser.buffer.set((int)bufferLen, (byte)0);
            bufferLen++;
            parser.unread++;
            break;
        }
    }

    while (bufferLen < length) {
        parser.buffer.set((int)bufferLen, (byte)0);
        bufferLen++;
    }
    parser.buffer = new ArrayList<>(parser.buffer.subList(0, (int)bufferLen));
    return true;
}

