private void parseTableIndexes(List<JsonObject> data, Map<String, TableSchema> tables) {
    Map<String, List<JsonObject>> indexData = new HashMap<>();

    // Group columns by table and index
    for (JsonObject row : data) {
        String tableName = Optional.ofNullable(row.get("table_name"))
                .map(JsonElement::getAsString)
                .orElse("");
        String indexName = Optional.ofNullable(row.get("index_name"))
                .map(JsonElement::getAsString)
                .orElse("");
        String key = tableName + ":" + indexName;

        indexData.computeIfAbsent(key, k -> new ArrayList<>()).add(row);
    }

    // Create index schemas and add to tables
    for (Map.Entry<String, List<JsonObject>> entry : indexData.entrySet()) {
        String key = entry.getKey();
        List<JsonObject> columns = entry.getValue();
        String[] parts = key.split(":", -1);
        if (parts.length >= 2) {
            String tableName = parts[0];
            String indexName = parts[1];

            if (tables.containsKey(tableName)) {
                TableSchema tableSchema = tables.get(tableName);
                List<String> indexColumns = new ArrayList<>();

                for (JsonObject column : columns) {
                    String columnName = Optional.ofNullable(column.get("column_name"))
                            .map(JsonElement::getAsString)
                            .orElse("");
                    indexColumns.add(columnName);
                }

                boolean isUnique = indexName.contains("unique") || indexName.contains("pk");
                IndexSchema indexSchema = new IndexSchema(indexName, indexColumns, isUnique);

                tableSchema.indexes.add(indexSchema);
                tables.put(tableName, tableSchema);
            }
        }
    }
}

