private func parseTableIndexes(data: Array<JsonObject>, tables: Map<String, TableSchema>) {
        let indexData = Map<String, Array<JsonObject>>()

        // Group columns by table and index
        for (row) in data {
            let tableName = row.get("table_name")?.stringValue ?? ""
            let indexName = row.get("index_name")?.stringValue ?? ""
            let key = "${tableName}:${indexName}"

            if (!indexData.contains(key)) {
                indexData[key] = Array<JsonObject>()
            }
            indexData[key]?.push(row)
        }

        // Create index schemas and add to tables
        for ((key, columns)) in indexData {
            let parts = key.split(":")
            if (parts.size >= 2) {
                let tableName = parts[0]
                let indexName = parts[1]

                if (tables.contains(tableName)) {
                    var tableSchema = tables[tableName]
                    let indexColumns = Array<String>()

                    for (column) in columns {
                        let columnName = column.get("column_name")?.stringValue ?? ""
                        indexColumns.push(columnName)
                    }

                    let indexSchema = IndexSchema(
                        name: indexName,
                        columns: indexColumns,
                        unique: indexName.contains("unique") || indexName.contains("pk")
                    )

                    tableSchema.indexes.push(indexSchema)
                    tables[tableName] = tableSchema
                }
            }
        }
    }

