private static ParseResult valueInteger(Token token) {
    if (!numUnderscoreOk(token.value)) {
        error("invalid integer '" + token.value + "': underscores must be surrounded by digits", token);
    }
    if (numHasLeadingZero(token.value)) {
        error("invalid integer '" + token.value + "': cannot have leading zeros", token);
    }

    try {
        long v = Long.parseLong(token.value.replace("_", ""));
        return new ParseResult(new DataModelInt(v), typeOfPrimitive(token));
    } catch (NumberFormatException e) {
        error("expected integer value, but got '" + token.value + "' instead.");
        return null; // unreachable due to error() throwing or terminating
    }
}

