import java.util.*;

class CompletionState {
    private List<String> completions;
    private int selectedIndex;
    private boolean isActive;

    public CompletionState() {
        this.completions = new ArrayList<>();
        this.selectedIndex = 0;
        this.isActive = false;
    }

    public void setCompletions(List<String> completions) {
        this.completions = new ArrayList<>(completions);
        this.selectedIndex = 0;
        this.isActive = !completions.isEmpty();
    }

    public void clear() {
        this.completions.clear();
        this.selectedIndex = 0;
        this.isActive = false;
    }

    public void moveUp() {
        if (this.isActive && !this.completions.isEmpty()) {
            this.selectedIndex = (this.selectedIndex > 0) ? this.selectedIndex - 1 : this.completions.size() - 1;
        }
    }

    public void moveDown() {
        if (this.isActive && !this.completions.isEmpty()) {
            this.selectedIndex = (this.selectedIndex + 1) % this.completions.size();
        }
    }

    public Optional<String> getSelected() {
        if (this.isActive && this.selectedIndex >= 0 && this.selectedIndex < this.completions.size()) {
            return Optional.of(this.completions.get(this.selectedIndex));
        }
        return Optional.empty();
    }
}

