public Session createSession() {
    if (isStoped()) {
        throw new TransportException("Endpoint stoped");
    }

    if (!started.get()) {
        throw new TransportException("The endpoint did not start yet, please call ClientTcpEndpoint::start first");
    }

    try {
        Connection conn = connectionPool.borrowObject();
        if (conn.isClosed()) {
            throw new TransportException("Connection closed");
        }

        return new DefaultSession(conn, filterChain);
    } catch (Exception ex) {
        logger.error(ex.getMessage(), ex);
        if (ex instanceof TransportException transportEx) {
            throw transportEx;
        }

        throw new TransportException("Failure to create session, error: " + ex.getMessage(), ex);
    }
}

