import java.lang.Math;

public class DistanceUtils {
    /**
     * 计算欧几里得距离
     */
    public static double euclidean(double[] a, double[] b) {
        double sum = 0.0;
        for (int i = 0; i < a.length; i++) {
            double diff = a[i] - b[i];
            sum += diff * diff;
        }
        return Math.sqrt(sum);
    }

    /**
     * 计算曼哈顿距离
     */
    public static double manhattan(double[] a, double[] b) {
        double sum = 0.0;
