public class WorkStealingDispatcher {
    private final int workerCount;
    private final WorkerThread[] workers;
    private final java.util.concurrent.ConcurrentLinkedQueue<ActorTask> globalQueue;
    private final java.util.concurrent.atomic.AtomicLong roundRobinCounter;
    private final java.util.concurrent.atomic.AtomicBoolean isStarted;
    private final java.util.concurrent.atomic.AtomicLong totalTasksSubmitted;
    private final java.util.concurrent.atomic.AtomicLong totalTasksCompleted;

    public WorkStealingDispatcher(int workerCount) {
        this.workerCount = workerCount;
        this.globalQueue = new java.util.concurrent.ConcurrentLinkedQueue<>();
        this.roundRobinCounter = new java.util.concurrent.atomic.AtomicLong(0);
        this.isStarted = new java.util.concurrent.atomic.AtomicBoolean(false);
        this.totalTasksSubmitted = new java.util.concurrent.atomic.AtomicLong(0);
        this.totalTasksCompleted = new java.util.concurrent.atomic.AtomicLong(0);

        // 创建工作线程
        this.workers = new WorkerThread[workerCount];
        for (int i = 0; i < workerCount; i++) {
            this.workers[i] = new WorkerThread((int) i, this.globalQueue);
        }

        // 设置工作线程之间的引用
        for (WorkerThread worker : this.workers) {
            worker.setOtherWorkers(this.workers);
        }
    }

    public void start() {
        if (isStarted.compareAndSet(false, true)) {
            for (WorkerThread worker : workers) {
                worker.start();
            }
            System.out.println("工作窃取调度器启动，工作线程数: " + workerCount);
        }
    }

    public void stop() {
        if (isStarted.compareAndSet(true, false)) {
            for (WorkerThread worker : workers) {
                worker.stop();
            }
            System.out.println("工作窃取调度器停止");
        }
    }

    public void dispatch(Envelope envelope, ActorRef actorRef) {
        dispatchWithPriority(envelope, actorRef, Priority.Normal);
    }

    public void dispatchWithPriority(Envelope envelope, ActorRef actorRef, Priority priority) {
        ActorTask task = new ActorTask(envelope, actorRef, priority);
        totalTasksSubmitted.incrementAndGet();

        // 尝试提交到负载最轻的工作线程
        WorkerThread targetWorker = selectWorker();

        if (!targetWorker.submitTask(task)) {
            // 本地队列满，提交到全局队列
            globalQueue.add(task);
        }
    }

    private WorkerThread selectWorker() {
        // 简单的轮询策略
        long index = roundRobinCounter.incrementAndGet() % workerCount;
        return workers[(int) index];
    }

    public int getWorkerCount() {
        return workerCount;
    }

    public long getTotalTasksSubmitted() {
        return totalTasksSubmitted.get();
    }

    public long getTotalTasksProcessed() {
        long total = 0;
        for (WorkerThread worker : workers) {
            total += worker.getTasksProcessed();
        }
        return total;
    }

    public long getGlobalQueueSize() {
        return globalQueue.size();
    }

    public WorkerStats[] getWorkerStats() {
        java.util.List<WorkerStats> stats = new java.util.ArrayList<>();
        for (WorkerThread worker : workers) {
            stats.add(new WorkerStats(
                worker.getWorkerId(),
                worker.getTasksProcessed(),
                worker.getLocalQueueSize(),
                worker.getStealAttempts(),
                worker.getSuccessfulSteals()
            ));
        }
        return stats.toArray(new WorkerStats[0]);
    }
}

