import java.util.*;

public class TurnEngine {
    private final Map<String, Turn> activeTurns;
    private final Map<String, TurnSession> sessions;
    private final List<String> turnHistory;
    private final long maxHistorySize = 50;
    private long nextTurnId;
    private boolean isInitialized;

    public TurnEngine() {
        activeTurns = new HashMap<>();
        sessions = new HashMap<>();
        turnHistory = new ArrayList<>();
        nextTurnId = 1;
        isInitialized = false;
    }

    /**
     * 初始化TurnEngine
     */
    public void initialize() {
        if (!isInitialized) {
            System.out.println("🔄 TurnEngine已初始化");
            System.out.println("📊 支持并发Turn管理和历史跟踪");
            isInitialized = true;

            // 发送初始化事件
            AgentExecutionEvent initEvent = new AgentExecutionEvent(
                    AgentEventType.SystemInitialized,
                    "TurnEngine初始化完成"
            );
            GlobalEventManager.dispatchAgentEvent(initEvent);
        }
    }

    /**
     * 创建新的Turn
     */
    public Turn createTurn(Agent agent, AgentRequest request) {
        return createTurnWithSession("default-session", agent, request);
    }

    /**
     * 创建带会话ID的Turn
     */
    public Turn createTurnWithSession(String sessionId, Agent agent, AgentRequest request) {
        Turn turn = new Turn(sessionId, agent, request);
        String turnId = turn.getTurnId();

        // 获取或创建会话
        TurnSession session = getOrCreateSession(sessionId);
        session.addTurn(turn);

        // 添加到活跃Turn列表
        activeTurns.put(turnId, turn);

        // 添加到历史记录
        addToHistory(turnId);

        System.out.println("🆕 创建新Turn: " + turnId + " (会话: " + sessionId + ")");

        return turn;
    }

    /**
     * 获取或创建会话
     */
    private TurnSession getOrCreateSession(String sessionId) {
        TurnSession session = sessions.get(sessionId);
        if (session != null) {
            return session;
        } else {
            session = new TurnSession(sessionId);
            sessions.put(sessionId, session);
            System.out.println("🆕 创建新会话: " + sessionId);
            return session;
        }
    }

    /**
     * 执行Turn并处理流式事件
     */
    public Turn executeTurn(Agent agent, AgentRequest request) {
        Turn turn = createTurn(agent, request);
        AbortSignal signal = new AbortSignal();

        // 在后台执行Turn
        // 注意：这里应该使用真正的异步执行，但为了简化实现，使用同步方式
        turn.runWithEvents(signal);

        return turn;
    }

    /**
     * 获取活跃Turn
     */
    public Optional<Turn> getActiveTurn(String turnId) {
        Turn turn = activeTurns.get(turnId);
        return Optional.ofNullable(turn);
    }

    /**
     * 移除完成的Turn
     */
    public void removeTurn(String turnId) {
        if (activeTurns.containsKey(turnId)) {
            activeTurns.remove(turnId);
            System.out.println("🗑️ 移除Turn: " + turnId);
        }
    }

    /**
     * 获取统计信息
     */
    public String getStats() {
        int activeTurnCount = activeTurns.size();
        int totalTurnCount = turnHistory.size();

        return "Turn统计: 活跃" + activeTurnCount + "个, 历史总计" + totalTurnCount + "个";
    }

    /**
     * 清理完成的Turn
     */
    public void cleanup() {
        List<String> completedTurns = new ArrayList<>();

        for (Map.Entry<String, Turn> entry : activeTurns.entrySet()) {
            String turnId = entry.getKey();
            Turn turn = entry.getValue();
            String status = turn.getStatus();
            if ("completed".equals(status) || "error".equals(status)) {
                completedTurns.add(turnId);
            }
        }

        for (String turnId : completedTurns) {
            removeTurn(turnId);
        }

        if (!completedTurns.isEmpty()) {
            System.out.println("🧹 清理了" + completedTurns.size() + "个完成的Turn");
        }
    }

    /**
     * 添加到历史记录
     */
    private void addToHistory(String turnId) {
        if (turnHistory.size() >= maxHistorySize) {
            // 移除最旧的记录（保留最新的 maxHistorySize-1 个）
            turnHistory.remove(0);
        }
        turnHistory.add(turnId);
    }
}

