     */
    public func removeTurn(turnId: String): Unit {
        match (activeTurns.get(turnId)) {
            case Some(_) =>
                activeTurns.remove(turnId)
                println("🗑️ 移除Turn: ${turnId}")
            case None => ()
        }
    }

