    }

    /**
     * 清理完成的Turn
     */
    public func cleanup(): Unit {
        let completedTurns = ArrayList<String>()

        for ((turnId, turn) in activeTurns) {
            let status = turn.getStatus()
            if (status == "completed" || status == "error") {
                completedTurns.add(turnId)
            }
        }

        for (turnId in completedTurns) {
            removeTurn(turnId)
        }

        if (!completedTurns.isEmpty()) {
            println("🧹 清理了${completedTurns.size}个完成的Turn")
        }
    }

    /**
