    private func addToHistory(turnId: String): Unit {
        if (turnHistory.size >= maxHistorySize) {
            // 移除最旧的记录
            let newHistory = ArrayList<String>()
            for (i in 1..turnHistory.size) {
                newHistory.add(turnHistory[i])
            }
            turnHistory = newHistory
        }

        turnHistory.add(turnId)
    }
