public class InTemplate extends HtmlTreeBuilderState {
    @Override
    public String toString() {
        return "InTemplate";
    }

    @Override
    protected boolean process(Token tk, HtmlTreeBuilder builder) {
        String name;
        switch (tk.typ) {
            case CharacterType:
            case CommentType:
            case DoctypeType:
                builder.process(tk, InBody);
                break;
            case StartTagType:
                return processStartTag(tk, builder);
            case EndTagType:
                name = tk.asEndTag().normalName();
                if ("template".equals(name)) {
                    builder.process(tk, InHead);
                } else {
                    builder.error(this);
                    return false;
                }
                break;
            case EOFType:
                // stop parsing if not in template stack
                if (!builder.onStack("template")) {
                    return true;
                }
                builder.error(this);
                builder.popStackToClose("template");
                builder.clearFormattingElementsToLastMarker();
                builder.popTemplateMode();
                builder.resetInsertionMode();

                // spec deviation - if we did not break out of Template, stop processing,
                // and don't worry about cleaning up ultra-deep template stacks
                // limited depth because this can recurse and will blow stack if too deep
                if (builder.state() == InTemplate && builder.templateModeSize() < 12) {
                    return builder.process(tk);
                } else {
                    return true;
                }
            default:
                // no-op for other token types
                break;
        }
        return true;
    }

    private boolean processStartTag(Token tk, HtmlTreeBuilder builder) {
        String name = tk.asStartTag().normalName();
        if (Constants.InTemplateToHead.contains(name)) {
            builder.process(tk, InHead);
        } else if (Constants.InTemplateToTable.contains(name)) {
            builder.popTemplateMode();
            builder.pushTemplateMode(InTable);
            builder.transition(InTable);
            return builder.process(tk);
        } else if ("col".equals(name)) {
            builder.popTemplateMode();
            builder.pushTemplateMode(InColumnGroup);
            builder.transition(InColumnGroup);
            return builder.process(tk);
        } else if ("tr".equals(name)) {
            builder.popTemplateMode();
            builder.pushTemplateMode(InTableBody);
            builder.transition(InTableBody);
            return builder.process(tk);
        } else if ("td".equals(name) || "th".equals(name)) {
            builder.popTemplateMode();
            builder.pushTemplateMode(InRow);
            builder.transition(InRow);
            return builder.process(tk);
        } else {
            builder.popTemplateMode();
            builder.pushTemplateMode(InBody);
            builder.transition(InBody);
            return builder.process(tk);
        }
        return true;
    }
}

public class AfterBody extends HtmlTreeBuilderState {
    @Override
    public String toString() {
        return "AfterBody";
    }

    @Override
    protected boolean process(Token tk, HtmlTreeBuilder builder) {
        if (isWhitespace(tk)) {
            // out of spec - include whitespace. spec would move into body
            builder.insert(tk.asCharacter());
        } else if (tk.isComment()) {
            // into html node
            builder.insert(tk.asComment());
        } else if (tk.isDoctype()) {
            builder.error(this);
            return false;
        } else if (tk.isStartTag() && "html".equals(tk.asStartTag().normalName())) {
            return builder.process(tk, InBody);
        } else if (tk.isEndTag() && "html".equals(tk.asEndTag().normalName())) {
            if (builder.isFragmentParsing()) {
                builder.error(this);
                return false;
            } else {
                if (builder.onStack("html")) {
                    builder.popStackToClose("html");
                }
                builder.transition(AfterAfterBody);
            }
        } else if (tk.isEOF()) {
            // chillax! we're done
        } else {
            builder.error(this);
            builder.resetBody();
            return builder.process(tk);
        }
        return true;
    }

    private boolean isWhitespace(Token tk) {
        if (!tk.isCharacter()) {
            return false;
        }
        char c = tk.asCharacter().getData().charAt(0);
        return Character.isWhitespace(c);
    }
}

