import java.lang.Math;

public class FFTUtils {
    public static Vector<Complex64> icfft(Vector<Complex64> data, String norm) {
        // Default norm is "backward" per仓颉 signature
        if (norm == null) {
            norm = "backward";
        }

        int n = data.size();
        double fct;
        if ("backward".equals(norm)) {
            fct = 1.0 / (double) n;
        } else if ("forward".equals(norm)) {
            fct = 1.0;
        } else if ("ortho".equals(norm)) {
            fct = 1.0 / Math.sqrt(n);
        } else {
            throw new IllegalArgumentException("icfft: unknown norm");
        }

        Vector<Complex64> dataCopy = data.copy();
        CFFTPlan plan = new CFFTPlan(n);
        plan.fftBackward(dataCopy, fct);
        return dataCopy;
    }

    // Overloaded method for default norm="backward"
    public static Vector<Complex64> icfft(Vector<Complex64> data) {
        return icfft(data, "backward");
    }
}

