import java.util.*;
import java.util.concurrent.locks.ReentrantLock;

public class SimpleMailbox implements Mailbox {
    private final List<Envelope> messages;
    private final long capacity;
    private final ReentrantLock mutex;

    public SimpleMailbox(long capacity) {
        this.messages = new ArrayList<>();
        this.capacity = capacity;
        this.mutex = new ReentrantLock();
    }

    public boolean enqueue(Envelope envelope) {
        mutex.lock();
        try {
            if (capacity > 0 && messages.size() >= capacity) {
                return false;
            }
            messages.add(envelope);
            return true;
        } finally {
            mutex.unlock();
        }
    }

    public Optional<Envelope> dequeue() {
        mutex.lock();
        try {
            if (messages.isEmpty()) {
                return Optional.empty();
            }
            Envelope envelope = messages.get(0);
            // Remove first element efficiently
            messages.remove(0);
            return Optional.of(envelope);
        } finally {
            mutex.unlock();
        }
    }

    public boolean isEmpty() {
        mutex.lock();
        try {
            return messages.isEmpty();
        } finally {
            mutex.unlock();
        }
    }

    public long size() {
        mutex.lock();
        try {
            return messages.size();
        } finally {
            mutex.unlock();
        }
    }

    public void clear() {
        mutex.lock();
        try {
            messages.clear();
        } finally {
            mutex.unlock();
        }
    }
}

