        if (range.hasStart) {
            start = range.start
        }

        var end = limitVal
        if (range.hasEnd) {
            end = range.end
        }

        if (!range.isClosed) {
            end = end - 1
        }

        return slice(index: start, length: (end - start) + 1)
    }

