func params_update_fn(params: Vector<Float64>, data: Matrix<Float64>, step_size: Float64, pre_matrix: Matrix<Float64>, module: McmcModule): Vector<Float64> {

    let n = params.size()

    let grad_out = empty<Float64>(n)

    // let gradTuple = valWithGrad(likelihood_dens, (params[0], params[1], data, module))[1]

    if(params.size() == 1) {
        let product_grad = grad(post_dens_grad_1, (params[0], data, module))
        grad_out[0] = product_grad
        // print("Gradient: ${product_grad}\n")
    }

    if(params.size() == 2) {
        let product_grad = grad(post_dens_grad_2, (params[0], params[1], data, module))
        grad_out[0] = product_grad[0]
        grad_out[1] = product_grad[1]
        // print("Gradient: ${product_grad[0]} ${product_grad[1]}\n")
    }

    if(params.size() == 3) {
        let product_grad = grad(post_dens_grad_3, (params[0], params[1], params[2], data, module))
        grad_out[0] = product_grad[0]
        grad_out[1] = product_grad[1]
        grad_out[2] = product_grad[2]
        // print("Gradient: ${product_grad[0]} ${product_grad[1]} ${product_grad[2]}\n")
    }

    return params + (step_size * step_size / 2.0) * (pre_matrix * grad_out)
}

