 *                     (shouldInclude: boolean, customName: String, token: Token)
 * @return The generated tokens
 */
public static Tokens generateMappers(Tokens name, ArrayList<VarDecl> vars,
        java.util.function.Function<String, java.util.Tuple3<Boolean, String, Token>> mapperMetaFn) {
    Tokens tokens = quote();
    for (int i = 0; i < vars.size(); i++) {
        if (i > 0) {
            tokens = tokens.plus(comma);
        }
        VarDecl decl = vars.get(i);
        Token varName = decl.identifier;
        Tokens dts = quote(decl.declType);
        java.util.Tuple3<Boolean, String, Token> meta = mapperMetaFn.apply(varName.value);
        tokens = tokens.plus(generateMappers(name, varName, dts, meta));
    }
    return tokens;
}

