public enum NodeState {
    JOINING,
    UP,
    LEAVING,
    DOWN,
    FAILED;

    private final java.time.LocalDateTime time;

    NodeState() {
        this.time = null;
    }

    NodeState(java.time.LocalDateTime time) {
        this.time = time;
    }

    public static NodeState joining(java.time.LocalDateTime time) {
        return new NodeState(time) {
            @Override
            public boolean isAvailable() {
                return false;
            }

            @Override
            public String toString() {
                return "Joining(" + time + ")";
            }
        };
    }

    public static NodeState up(java.time.LocalDateTime time) {
        return new NodeState(time) {
            @Override
            public boolean isAvailable() {
                return true;
            }

            @Override
            public String toString() {
                return "Up(" + time + ")";
            }
        };
    }

    public static NodeState leaving(java.time.LocalDateTime time) {
        return new NodeState(time) {
            @Override
            public boolean isAvailable() {
                return false;
            }

            @Override
            public String toString() {
                return "Leaving(" + time + ")";
            }
        };
    }

    public static NodeState down(java.time.LocalDateTime time) {
        return new NodeState(time) {
            @Override
            public boolean isAvailable() {
                return false;
            }

            @Override
            public String toString() {
                return "Down(" + time + ")";
            }
        };
    }

    public static NodeState failed(java.time.LocalDateTime time) {
        return new NodeState(time) {
            @Override
            public boolean isAvailable() {
                return false;
            }

            @Override
            public String toString() {
                return "Failed(" + time + ")";
            }
        };
    }

    public abstract boolean isAvailable();

    public abstract String toString();
}

