private Result<DatabaseResult, DatabaseError> executeBatchInternal(String statements, QueryOptions options) {
    long startTime = System.nanoTime();

    Result<Integer, String> connectionResult = connection != null ? connection.execute(statements, new String[0]) : null;

    if (connectionResult == null || connectionResult.isErr()) {
        return Result.err(new DatabaseError("BATCH_FAILED", "Batch execution failed"));
    }

    long duration = System.nanoTime() - startTime;
