private func executeBatchInternal(statements: String, options: QueryOptions) -> Result<DatabaseResult, DatabaseError> {
        let startTime = Time.current()

        let connectionResult = connection?.execute(statements, Array<String>())

        if (connectionResult is Err) {
            return Err<DatabaseResult, DatabaseError>(DatabaseError(
                code: "BATCH_FAILED",
                message: "Batch execution failed"
            ))
        }

        let duration = Time.current().difference(startTime)
        let affectedRows = (connectionResult as Ok<Int64, String>).value

        return Ok<DatabaseResult, DatabaseError>(DatabaseResult(
            affectedRows: affectedRows,
            executionTime: duration
        ))
    }

