public class ScientificNotation {
    public static class Result {
        public final String signal;
        public final String integerStr;
        public final String fractionalStr;
        public final long exponent;

        public Result(String signal, String integerStr, String fractionalStr, long exponent) {
            this.signal = signal;
            this.integerStr = integerStr;
            this.fractionalStr = fractionalStr;
            this.exponent = exponent;
        }
    }

    public static Result scientificNotation(String amount, long fraction, long integerLen, long fractionalLen) {
        String signal;
        String positiveAmount;
        if (amount.charAt(0) == '-') {
            signal = "-";
            positiveAmount = amount.substring(1);
        } else {
            signal = "+";
            positiveAmount = amount;
        }

        // 构造整数部分和小数部分
        String integerPart;
        String fractionalPart;
        if (positiveAmount.length() > fraction) {
            int splitIndex = positiveAmount.length() - (int) fraction;
            integerPart = positiveAmount.substring(0, splitIndex);
            fractionalPart = positiveAmount.substring(splitIndex);
        } else {
            integerPart = "0";
            int zerosNeeded = (int) (fraction - positiveAmount.length());
            fractionalPart = "0".repeat(zerosNeeded) + positiveAmount;
        }

        String mergedStr = integerPart + fractionalPart;
        int originalPoint = integerPart.length();

        // 找到第一个非零字符的位置
        int firstNonZero = -1;
        for (int index = 0; index < mergedStr.length(); index++) {
            if (mergedStr.charAt(index) != '0') {
                firstNonZero = index;
                break;
            }
        }

        // 处理全零的情况
        if (firstNonZero == -1) {
            return new Result("+", "0", "", 0);
        }

        String fractionalStr;
        String integerStr;
        long exponent;
        if (integerLen > 0) {
            // 计算新的小数点的位置
            int newPoint = firstNonZero + (int) integerLen;
            int start = firstNonZero;
            int end = Math.min(start + (int) integerLen, mergedStr.length());

            // 提取整数部分并补零
            integerStr = mergedStr.substring(start, end);

            if (integerStr.length() < integerLen) {
                integerStr += "0".repeat((int) (integerLen - integerStr.length()));
            }

            // 剩余部分作为小数部分
            fractionalStr = end < mergedStr.length() ? mergedStr.substring(end) : "";

            // 计算指数
            exponent = originalPoint - newPoint;
        } else {
            // 整数部分为0的特殊处理
            int newPoint = firstNonZero;
            integerStr = "0";
            fractionalStr = mergedStr.substring(newPoint);
            exponent = originalPoint - newPoint;
        }

        // 截断小数部分到指定长度
        if (fractionalStr.length() > fractionalLen) {
            fractionalStr = fractionalStr.substring(0, (int) fractionalLen);
        }

        return new Result(signal, integerStr, fractionalStr, exponent);
    }
}

