import java.util.*;

public class ShuffleUtil {
    public static <T> List<T> shuffle(Iterator<T> xs, Random rng) {
        // 先收集所有元素
        List<T> arr = new ArrayList<>();
        while (xs.hasNext()) {
            arr.add(xs.next());
        }

        if (arr.size() <= 1) {
            return arr;
        }

        // Fisher-Yates 洗牌
        int i = arr.size() - 1;
        while (i > 0) {
            long nextLong = rng.nextLong();
            // Use Math.abs with care: Long.MIN_VALUE abs is still negative, so we use unsigned mod via & mask
            // Instead, we do bounded nextInt to avoid overflow and simplify
            int j = Math.abs((int) nextLong) % (i + 1);

            // 交换
            if (i != j) {
                T tmp = arr.get(i);
                arr.set(i, arr.get(j));
                arr.set(j, tmp);
            }
            i--;
        }

        return arr;
    }
}

