public func shuffle<T>(xs: Iterator<T>, rng: RNG): ArrayList<T> {
    // 先收集所有元素
    let arr = ArrayList<T>()
    while (let size(x) <- xs.next()) {
        arr.add(x)
    }

    if (arr.size <= 1) {
        return arr
    }

    // Fisher-Yates 洗牌
    var i = arr.size - 1
    while (i > 0) {
        let j = absInt64(rng.nextInt()) % (i + 1)

        // 交换
        if (i != j) {
            let tmp = arr[i]
            arr[i] = arr[j]
            arr[j] = tmp
        }
        i -= 1
    }

    return arr
}

