import java.time.Duration;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.atomic.AtomicLong;

public class TimerScheduler {
    private static final int SCHEDULER_COUNT = 64;
    private static final TimerScheduler[] schedulers = new TimerScheduler[SCHEDULER_COUNT];

    static {
        for (int i = 0; i < SCHEDULER_COUNT; i++) {
            schedulers[i] = new TimerScheduler();
        }
    }

    public static TimerScheduler getScheduler(long id) {
        return schedulers[(int) (id % SCHEDULER_COUNT)];
    }

    private final TimerQueue queue = new TimerQueue();
    private volatile TimerHeap heap = new TimerHeap();

    // Notification mechanism - for cjc_version >= "1.0.0"
    private final ReentrantLock mtx = new ReentrantLock();
    private final Condition condition = mtx.newCondition();

    private void mtxNotify() {
        mtx.lock();
        try {
            condition.signal();
        } finally {
            mtx.unlock();
        }
    }

    private void mtxWait(Duration timeout) {
        mtx.lock();
        try {
            if (timeout == Duration.ofNanos(Long.MAX_VALUE)) {
                condition.await();
            } else {
                condition.awaitNanos(timeout.toNanos());
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        } finally {
            mtx.unlock();
        }
    }

    private final AtomicBoolean isRunning = new AtomicBoolean(false);
    private final AtomicLong cancelCount = new AtomicLong(0);

    public void add(RTimer timer) {
        if (!timer.isEnabled()) {
            if (timer.complete != null) {
                timer.complete.run();
            }
            return;
        }
        if (MonoTime.now().isAfter(timer.endTime)) {
            execute(timer);
            return;
        }
        queue.add(timer);
        mtxNotify();
        start();
    }

    private void start() {
        if (!isRunning.compareAndSet(false, true)) {
            return;
        }
        new Thread(() -> {
            while (true) {
                consume();
                schedule();
                long count = cancelCount.get();
                // Refer to the general implementation in the industry for determining whether to clear the cancelled Timers.
                if (count > heap.size() / 4 && count > 10) {
                    clearCancelledTimers();
                }
            }
        }).start();
    }

    private void consume() {
        RTimer t;
        while ((t = queue.remove()) != null) {
            heap.add(t);
        }
    }

    private void schedule() {
        if (heap.isEmpty()) {
            mtx.lock();
            try {
                if (queue.isEmpty()) {
                    mtxWait(Duration.ofNanos(Long.MAX_VALUE));
                }
            } finally {
                mtx.unlock();
            }
            return;
        }
        RTimer timer = heap.top();
        if (!timer.isEnabled()) {
            if (timer.complete != null) {
                timer.complete.run();
            }
            heap.poll();
            cancelCount.addAndGet(-1);
            return;
        }

        MonoTime time = MonoTime.now();
        if (time.isAfter(timer.endTime) || time.equals(timer.endTime)) {
            execute(timer);
            heap.poll();
            return;
        }
        mtx.lock();
        try {
            mtxWait(Duration.between(time, timer.endTime));
        } finally {
            mtx.unlock();
        }
    }

    private void execute(RTimer timer) {
        new Thread(() -> {
            Duration duration = null;
            try {
                timer.task.run();
            } catch (Exception e) {
                // 遇到异常就打印异常内容
                e.printStackTrace();
                // 并且结束本 Timer
                duration = null;
            }
            if (duration != null) {
                timer.nextRound(duration);
            } else {
                timer.setEnabled(false);
                if (timer.complete != null) {
                    timer.complete.run();
                }
            }
        }).start();
    }

    public void addCancelCount() {
        cancelCount.incrementAndGet();
    }

    private void clearCancelledTimers() {
        cancelCount.set(0);
        TimerHeap source = heap;
        heap = new TimerHeap();
        RTimer timer;
        while ((timer = source.poll()) != null) {
            if (timer.isEnabled()) {
                heap.add(timer);
            }
        }
    }
}

