class TimerScheduler {
    private static const SCHEDULER_COUNT = 64
    private static let schedulers: Array<TimerScheduler>
    static init() {
        schedulers = Array<TimerScheduler>(SCHEDULER_COUNT) {_ => TimerScheduler()}
    }
    static func getScheduler(id: Int64) {
        schedulers[id % SCHEDULER_COUNT]
    }

    private let queue = TimerQueue()
    private var heap = TimerHeap()
    // 通知机制 - 新{
    @When[cjc_version >= "1.0.0"]
    private let mtx = Mutex()
    @When[cjc_version >= "1.0.0"]
    private let condition:Condition = synchronized(mtx) { mtx.condition() }
    @When[cjc_version >= "1.0.0"]
    private func mtxNotify(){ condition.notify() }
    @When[cjc_version >= "1.0.0"]
    private func mtxWait(timeout!: Duration = Duration.Max){ condition.wait(timeout:timeout) }
    // }
    // 通知机制 - 旧{
    @When[cjc_version < "1.0.0"]
    private let mtx = Monitor()
    @When[cjc_version < "1.0.0"]
    private func mtxNotify(){ mtx.notify() }
    @When[cjc_version < "1.0.0"]
    private func mtxWait(timeout!: Duration = Duration.Max){ mtx.wait(timeout:timeout) }
    // }

    private let isRunning = AtomicBool(false)
    private let cancelCount = AtomicInt64(0)

    func add(timer: RTimer) {
        if (!timer.isEnabled) {
            timer.complete?()
            return
        }
        if (MonoTime.now() > timer.endTime) {
            execute(timer)
            return
        }
        synchronized(mtx) {
            queue.add(timer)
            mtxNotify()
        }
        start()
    }

    private func start() {
        if (!isRunning.compareAndSwap(false, true)) {
            return
        }
        spawn {
            while (true) {
                consume()
                schedule()
                let count = cancelCount.load()
                // Refer to the general implementation in the industry for determining whether to clear the cancelled Timers.
                if (count > heap.size / 4 && count > 10) {
                    clearCancelledTimers()
                }
            }
        }
    }

    private func consume() {
        while (let Some(t) <- queue.remove()) {
            heap.add(t)
        }
    }

    private func schedule(): Unit {
        if (heap.isEmpty) {
            synchronized(mtx) {
                if (queue.isEmpty()) {
                    mtxWait()
                }
            }
            return
        }
        let timer = heap.top()
        if (!timer.isEnabled) {
            timer.complete?()
            heap.poll()
            cancelCount.fetchSub(1)
            return
        }

        let time = MonoTime.now()
        if (time >= timer.endTime) {
            execute(timer)
            heap.poll()
            return
        }
        synchronized(mtx) {
            mtxWait(timeout: timer.endTime - time)
        }
    }

    private func execute(timer: RTimer) {
        spawn {
            let duration = try {
                timer.task()
            } catch(e:Exception) {
                // 遇到异常就打印异常内容
                // e.printStackTrace()
                // 并且结束本 Timer
                Option<Duration>.None
            }
            if (let Some(d) <- duration) {
                timer.nextRound(d)
            }else{
                timer.isEnabled = false
                timer.complete?()
            }
        }
    }

    func addCancelCount() {
        cancelCount.fetchAdd(1)
    }

    private func clearCancelledTimers() {
        cancelCount.store(0)
        let source = heap
        heap = TimerHeap()
        while (!source.isEmpty) {
            let timer = source.poll()
            if (timer.isEnabled) {
                heap.add(timer)
            }
        }
    }
}

