public <T extends java.lang.Object> void append(LogLevel level, String message, java.util.TreeMap<String, T> args, Exception ex) {
    append(level, () -> {
        LoggerConfig.Filter filter = LoggerConfig.getFilter();
        if (filter instanceof LoggerConfig.DummyLogFilter) {
            return TextTemplate.compile(message, "{", "}").format(args);
        }
        java.util.HashMap<String, String> map = new java.util.HashMap<>();
        for (java.util.Map.Entry<String, T> entry : args.entrySet()) {
            String n = entry.getKey();
            T v = entry.getValue();
            java.util.Optional<java.util.Map.Entry<String, String>> filtered = filter.filter(n, v.toString());
            if (filtered.isPresent()) {
                java.util.Map.Entry<String, String> result = filtered.get();
                map.put(result.getKey(), result.getValue());
            }
        }
        return TextTemplate.compile(message, "{", "}").format(map);
    }, ex);
}

