import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;
import java.util.Arrays;
import java.util.List;

public class ByteConverter {
    public static byte[] convertToBytes(Object inputData) {
        if (inputData instanceof Boolean) {
            return getBytes((Boolean) inputData);
        } else if (inputData instanceof Character) { // Rune maps to char in Java
            return getBytes((Character) inputData);
        } else if (inputData instanceof String) {
            return getBytes((String) inputData);
        } else if (inputData instanceof Byte) {
            return getBytes((Byte) inputData);
        } else if (inputData instanceof Short) {
            return getBytes((Short) inputData);
        } else if (inputData instanceof Integer) {
            return getBytes((Integer) inputData);
        } else if (inputData instanceof Long) {
            return getBytes((Long) inputData);
        } else if (inputData instanceof java.lang.Character) { // unsigned types handled via wrapper or direct cast
            // Note: Java has no native unsigned primitives; assuming UInt8/16/32/64 are represented as byte/short/int/long
            // and treated as unsigned during conversion logic.
            if (inputData instanceof Byte) {
                return getBytes((Byte) inputData);
            } else if (inputData instanceof Short) {
                return getBytes((Short) inputData);
            } else if (inputData instanceof Integer) {
                return getBytes((Integer) inputData);
            } else if (inputData instanceof Long) {
                return getBytes((Long) inputData);
            }
        } else if (inputData instanceof Float) {
            return getBytes((Float) inputData);
        } else if (inputData instanceof Double) {
            return getBytes((Double) inputData);
        } else if (inputData instanceof char[]) {
            return convertRunesToBytes(Arrays.asList((char[]) inputData));
        } else if (inputData instanceof char[]) {
            return convertRunesToBytes(Arrays.asList((char[]) inputData));
        } else if (inputData instanceof List<?>) {
            List<?> list = (List<?>) inputData;
            if (list.isEmpty()) {
                return new byte[0];
            }
            Object first = list.get(0);
            if (first instanceof Character) {
                return convertRunesToBytes(list);
            } else if (first instanceof Byte) {
                return convertInt8sToBytes(list);
            } else if (first instanceof Short) {
                return convertInt16sToBytes(list);
            } else if (first instanceof Integer) {
                return convertInt32sToBytes(list);
            } else if (first instanceof Long) {
                return convertInt64sToBytes(list);
            } else if (first instanceof Float) {
                return convertFloat32sToBytes(list);
            } else if (first instanceof Double) {
                return convertFloat64sToBytes(list);
            }
        } else if (inputData instanceof byte[]) {
            return (byte[]) inputData;
        }

        throw new UnsupportedOperationException("Unsupported type " + inputData.getClass().getName());
    }

    private static byte[] getBytes(boolean value) {
        return new byte[]{(byte) (value ? 1 : 0)};
    }

    private static byte[] getBytes(char value) {
        return String.valueOf(value).getBytes(StandardCharsets.UTF_8);
    }

    private static byte[] getBytes(String value) {
        return value.getBytes(StandardCharsets.UTF_8);
    }

    private static byte[] getBytes(byte value) {
        return new byte[]{value};
    }

    private static byte[] getBytes(short value) {
        return ByteBuffer.allocate(2).putShort(value).array();
    }

    private static byte[] getBytes(int value) {
        return ByteBuffer.allocate(4).putInt(value).array();
    }

    private static byte[] getBytes(long value) {
        return ByteBuffer.allocate(8).putLong(value).array();
    }

    private static byte[] getBytes(float value) {
        return ByteBuffer.allocate(4).putFloat(value).array();
    }

    private static byte[] getBytes(double value) {
        return ByteBuffer.allocate(8).putDouble(value).array();
    }

    private static byte[] convertRunesToBytes(List<Character> runes) {
        StringBuilder sb = new StringBuilder();
        for (char c : runes) {
            sb.append(c);
        }
        return sb.toString().getBytes(StandardCharsets.UTF_8);
    }

    private static byte[] convertInt8sToBytes(List<Byte> values) {
        byte[] result = new byte[values.size()];
        for (int i = 0; i < values.size(); i++) {
            result[i] = values.get(i);
        }
        return result;
    }

    private static byte[] convertInt16sToBytes(List<Short> values) {
        ByteBuffer bb = ByteBuffer.allocate(2 * values.size());
        for (short v : values) {
            bb.putShort(v);
        }
        return bb.array();
    }

    private static byte[] convertInt32sToBytes(List<Integer> values) {
        ByteBuffer bb = ByteBuffer.allocate(4 * values.size());
        for (int v : values) {
            bb.putInt(v);
        }
        return bb.array();
    }

    private static byte[] convertInt64sToBytes(List<Long> values) {
        ByteBuffer bb = ByteBuffer.allocate(8 * values.size());
        for (long v : values) {
            bb.putLong(v);
        }
        return bb.array();
    }

    private static byte[] convertFloat32sToBytes(List<Float> values) {
        ByteBuffer bb = ByteBuffer.allocate(4 * values.size());
        for (float v : values) {
            bb.putFloat(v);
        }
        return bb.array();
    }

    private static byte[] convertFloat64sToBytes(List<Double> values) {
        ByteBuffer bb = ByteBuffer.allocate(8 * values.size());
        for (double v : values) {
            bb.putDouble(v);
        }
        return bb.array();
    }
}

