import java.util.Arrays;

public class LinearAlgebra {

    // Native LAPACK binding (to be implemented via JNI or JNA)
    private static native long LAPACKE_dgetrf(int matrixLayout, int m, int n,
                                              double[] a, int lda, int[] ipiv);

    // Constants
    private static final int LAPACK_COL_MAJOR = 102;

    /**
     * Performs LU decomposition with partial pivoting on a square matrix.
     * Returns (P, L, U) such that P * A = L * U.
     *
     * @param a input square matrix (double[][]), modified in-place during decomposition
     * @return triple of matrices: (permutation matrix P, lower triangular L, upper triangular U)
     * @throws IllegalArgumentException if input matrix is not square
     */
    public static class LUDecomposition {
        public final double[][] p;
        public final double[][] l;
        public final double[][] u;

        public LUDecomposition(double[][] p, double[][] l, double[][] u) {
            this.p = p;
            this.l = l;
            this.u = u;
        }
    }

    public static LUDecomposition lu(double[][] a) {
        if (a == null) {
            throw new IllegalArgumentException("lu: input matrix cannot be null");
        }
        int m = a.length;
        if (m == 0) {
            throw new IllegalArgumentException("lu: input matrix cannot be empty");
        }
        int n = a[0].length;
        for (double[] row : a) {
            if (row == null || row.length != n) {
                throw new IllegalArgumentException("lu: input matrix must be rectangular");
            }
        }
        if (m != n) {
            throw new IllegalArgumentException("lu: input must be square matrix");
        }

        // Copy input matrix for safe manipulation
        double[][] aCopy = new double[m][n];
        for (int i = 0; i < m; i++) {
            System.arraycopy(a[i], 0, aCopy[i], 0, n);
        }

        int[] ipiv = new int[Math.min(m, n)];
        long info = LAPACKE_dgetrf(LAPACK_COL_MAJOR, m, n, flatten(aCopy), m, ipiv);

        if (info != 0) {
            throw new RuntimeException("LAPACKE_dgetrf failed with info = " + info);
        }

        // Initialize L and U as copies of A
        double[][] l = new double[m][n];
        double[][] u = new double[m][n];
        for (int i = 0; i < m; i++) {
            System.arraycopy(aCopy[i], 0, l[i], 0, n);
            System.arraycopy(aCopy[i], 0, u[i], 0, n);
        }

        // Build L (unit lower triangular) and U (upper triangular)
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (i < j) {
                    l[i][j] = 0.0;
                } else if (i == j) {
                    l[i][j] = 1.0;
                } else { // i > j
                    u[i][j] = 0.0;
                }
            }
        }

        // Construct permutation vector (1-indexed pivot indices → 0-indexed permutation)
        int[] perm = new int[min(m, n)];
        for (int i = 0; i < perm.length; i++) {
            perm[i] = i;
        }
        for (int i = 0; i < ipiv.length; i++) {
            // ipiv[i] is 1-based index; convert to 0-based
            int pivotIdx = ipiv[i] - 1;
            if (pivotIdx < 0 || pivotIdx >= perm.length) {
                throw new RuntimeException("Invalid pivot index from LAPACK: " + ipiv[i]);
            }
            int temp = perm[i];
            perm[i] = perm[pivotIdx];
            perm[pivotIdx] = temp;
        }

        // Build permutation matrix P (size min(m,n) x min(m,n))
        double[][] p = new double[perm.length][perm.length];
        for (int i = 0; i < perm.length; i++) {
            p[perm[i]][i] = 1.0;
        }

        return new LUDecomposition(p, l, u);
    }

    // Helper to flatten 2D double array in column-major order (LAPACK expects this for COL_MAJOR)
    private static double[] flatten(double[][] matrix) {
        int m = matrix.length;
        int n = matrix[0].length;
        double[] flat = new double[m * n];
        for (int j = 0; j < n; j++) {
            for (int i = 0; i < m; i++) {
                flat[i + j * m] = matrix[i][j];
            }
        }
        return flat;
    }

    // Utility to create zero matrix
    private static double[][] zeros(int rows, int cols) {
        double[][] z = new double[rows][cols];
        for (int i = 0; i < rows; i++) {
            Arrays.fill(z[i], 0.0);
        }
