private void checkCapacity(long minNewSize) {
    // Validate that the requested size is at least the current length
    if (minNewSize < length) {
        throw new IllegalArgumentException("minNewSize must be >= length");
    }

    long curCap = keys.length;
    if (curCap >= minNewSize) {
        return;
    }

    long newCap;
    if (curCap >= INITIAL_CAPACITY) {
        newCap = length * GROWTH_FACTOR;
    } else {
        newCap = INITIAL_CAPACITY;
    }

    if (minNewSize > newCap) {
        newCap = minNewSize;
    }

    // Create new arrays
    String[] keysNew = new String[(int) newCap];
    java.util.Optional<Object>[] valsNew = new java.util.Optional[(int) newCap];

    // Initialize new arrays
    java.util.Arrays.fill(keysNew, "");
    java.util.Arrays.fill(valsNew, java.util.Optional.empty());

    // Copy existing elements
    System.arraycopy(keys, 0, keysNew, 0, (int) keys.length);
    System.arraycopy(vals, 0, valsNew, 0, (int) keys.length);

    // Update references
    keys = keysNew;
    vals = valsNew;
}

