public void clearDeliveredMessages() {
    if (clearDeliveredListVal) {
        synchronized (deliveredMessagesMutex) {
            if (clearDeliveredListVal) {
                if (!deliveredMessages.isEmpty()) {
                    if (session.isTransacted()) {
                        captureDeliveredMessagesForDuplicateSuppressionWithRequireRedelivery(true);
                    } else {
                        if (session.isClientAcknowledge()) {
                            logger.debug(
                                "{} rolling back delivered list ({}) on transport interrupt",
                                consumerId, deliveredMessages.size()
                            );

                            // 允许重新投递
                            if (!this.info.browser) {
                                for (MessageDispatch md : deliveredMessages) {
                                    if (md.getMessage() != null) {
                                        this.session.connection.rollbackDuplicate(this, md.getMessage());
                                    }
                                }
                            }
                        }
                        logger.debug(
                            "{} clearing delivered list ({}) on transport interrupt",
                            consumerId, deliveredMessages.size()
                        );
                        deliveredMessages.clear();
                        pendingAck = null;
                    }
                }
            }
            clearDeliveredListVal = false;
        }
    }
}

