            // @TRACE 400=>key={0} timeout={1} sent={2} completed={3} hasException={4} response={5} token={6}
            let params: Array<ToString> = [getKey(), timeout, sent, completed, exception.isSome(), response, this]
            if (let Some(e) <- exception) {
