                if (this.exception.isNone()) {
                    try {
                        // @TRACE 408=key={0} wait max={1}
                        log.trace(CLASS_NAME, methodName, "408", [getKey(), timeout])

                        if (timeout.isNone()) {
                            responseLockCondition.wait()
                        } else {
                            responseLockCondition.wait(timeout: timeout())
                        }
                    } catch (e: Exception) {
                        exception = MqttException(e)
                    }
                }
                if (!this.completed) {
                    if (let Some(e) <- exception) {
                        // @TRACE 401=failed with exception
                        log.trace(CLASS_NAME, methodName, "401", None, e)
                        throw e
                    }

                    if (timeout.isSome()) {
                        // time up and still not completed
                        break
                    }
                }
            }
        }
        // @TRACE 402=key={0} response={1}
        log.trace(CLASS_NAME, methodName, "402", [getKey(), this.response])
        return this.response
    }

