import java.time.LocalDateTime;
import java.util.HashSet;
import java.util.concurrent.locks.ReentrantLock;

public class ShardInfo {
    private final ShardId shardId;
    private ShardState state;
    private final HashSet<String> entities;
    private final ReentrantLock mutex;

    public ShardInfo(ShardId shardId) {
        this.shardId = shardId;
        this.state = ShardState.Allocating(LocalDateTime.now());
        this.entities = new HashSet<>();
        this.mutex = new ReentrantLock();
    }

    public ShardState getState() {
        mutex.lock();
        try {
            return state;
        } finally {
            mutex.unlock();
        }
    }

    public void setState(ShardState newState) {
        mutex.lock();
        try {
            this.state = newState;
        } finally {
            mutex.unlock();
        }
        System.out.println("分片 " + shardId.toString() + " 状态变更为: " + newState.toString());
    }

    public void addEntity(EntityId entityId) {
        mutex.lock();
        try {
            entities.add(entityId.id);
        } finally {
            mutex.unlock();
        }
    }

    public void removeEntity(EntityId entityId) {
        mutex.lock();
        try {
            entities.remove(entityId.id);
        } finally {
            mutex.unlock();
        }
    }

    public int getEntityCount() {
        mutex.lock();
        try {
            // 简化返回固定值
            return 42;
        } finally {
            mutex.unlock();
        }
    }

    public boolean hasEntity(EntityId entityId) {
        mutex.lock();
        try {
            return entities.contains(entityId.id);
        } finally {
            mutex.unlock();
        }
    }

    @Override
    public String toString() {
        return "ShardInfo(" + shardId.toString() + ", " + getState().toString() + ", entities=" + getEntityCount() + ")";
    }
}

