public class NillableStringResponseBuilder implements ResponseBuilder<String> {
    @Override
    public String build(RedisMessage message) {
        if (message instanceof StringRedisMessage stringMessage) {
            return stringMessage.getValue();
        } else if (message instanceof BulkStringRedisMessage bulkMessage) {
            return bulkMessage.getStringValue();
        } else if (message instanceof NullRedisMessage nullMessage) {
            return null;
        } else if (message instanceof ErrorRedisMessage errorMessage) {
            throw new RedisException(errorMessage.getValue());
        }

        throw new RedisException("Unsupported message type: " + message.getType());
    }
}

