public class Int16ToUInt64Converter extends Converter {
    @Override
    public Object convert(Object value) {
        if (value instanceof Short) {
            short intValue = (Short) value;
            // Convert signed 16-bit integer to unsigned 64-bit integer interpretation
            // i.e., treat the bit pattern as unsigned: [0, 65535] → same numeric value in long
            return ((long) intValue) & 0xFFFFL;
        }
        throw new IllegalArgumentException("The arg is not a Int16 type");
    }
}

