public ByteString substring(long beginIndex, long endIndex) {
    if (beginIndex < 0) {
        throw new IllegalArgumentException("beginIndex < 0");
    }
    if (endIndex > this.data.length) {
        throw new IllegalArgumentException("endIndex > size(" + this.data.length + ")");
    }
    long subLen = endIndex - beginIndex;
    if (subLen < 0) {
        throw new IllegalArgumentException("endIndex : " + endIndex + " < beginIndex : " + beginIndex);
    }
    if (beginIndex == 0 && endIndex == this.data.length) {
        return this;
    }
    byte[] copy = new byte[(int) subLen];
    System.arraycopy(this.data, (int) beginIndex, copy, 0, (int) subLen);
    return new ByteString(copy);
}

