public class ByteConverter {
    // ENDIAN == 1 means little-endian, otherwise big-endian
    private static final int ENDIAN = 1; // 小端序 保留

    public static byte[] uInt64ToByteArr(long unicodeStr) {
        byte[] result = new byte[8];
        if (ENDIAN == 1) { // 小端序
            result[0] = (byte) ((unicodeStr >> 56) & 0xFF);
            result[1] = (byte) ((unicodeStr >> 48) & 0xFF);
            result[2] = (byte) ((unicodeStr >> 40) & 0xFF);
            result[3] = (byte) ((unicodeStr >> 32) & 0xFF);
            result[4] = (byte) ((unicodeStr >> 24) & 0xFF);
            result[5] = (byte) ((unicodeStr >> 16) & 0xFF);
            result[6] = (byte) ((unicodeStr >> 8) & 0xFF);
            result[7] = (byte) (unicodeStr & 0xFF);
        } else { // 大端序 -> 小端序（即按大端序字节顺序存入小端序数组，等价于反转字节）
            result[0] = (byte) (unicodeStr & 0xFF);
            result[1] = (byte) ((unicodeStr >> 8) & 0xFF);
            result[2] = (byte) ((unicodeStr >> 16) & 0xFF);
            result[3] = (byte) ((unicodeStr >> 24) & 0xFF);
            result[4] = (byte) ((unicodeStr >> 32) & 0xFF);
            result[5] = (byte) ((unicodeStr >> 40) & 0xFF);
            result[6] = (byte) ((unicodeStr >> 48) & 0xFF);
            result[7] = (byte) ((unicodeStr >> 56) & 0xFF);
        }
        return result;
    }
}

