import java.util.Arrays;

/**
 * Flattens a matrix into a vector in row-major or column-major order.
 * @param <T> the numeric type of the matrix elements, must extend Number
 */
public class MatrixUtils {

    /**
     * Flattens a matrix into a vector.
     *
     * @param a the input matrix
     * @param order if true, uses row-major order (default); if false, uses column-major order
     * @param <T> the numeric type of the matrix elements
     * @return a flattened vector containing all elements of the matrix
     */
    public static <T extends Number> Vector<T> flatten(Matrix<T> a, boolean order) {
        int n = a.size();
        Vector<T> res = Vector.zeros(n);
        int row = a.getRows();
        int col = a.getCols();

        if (order) {
            for (int i = 0; i < row; i++) {
                for (int j = 0; j < col; j++) {
                    res.set(i * col + j, a.get(i, j));
                }
            }
        } else {
            for (int j = 0; j < col; j++) {
                for (int i = 0; i < row; i++) {
                    res.set(j * row + i, a.get(i, j));
                }
            }
        }

        return res;
    }

    /**
     * Overloaded version with default order = true (row-major)
     */
    public static <T extends Number> Vector<T> flatten(Matrix<T> a) {
        return flatten(a, true);
    }
}

