import java.util.*;

public class ColoringRepresentation<V, E> {
    protected final List<List<V>> colorClasses;
    protected final List<List<V>> positiveDegreeColorClasses;
    protected final long[] maxColorDegree;
    protected final long[] minColorDegree;

    protected final Map<V, Long> colorDegree;
    protected final Map<V, Long> coloring;
    protected long lastUsedColor;

    public ColoringRepresentation(Graph<V, E> graph, Coloring<V> alpha) {
        int n = graph.vertexSet().size();
        this.colorClasses = new ArrayList<>(n);
        this.positiveDegreeColorClasses = new ArrayList<>(n);
        this.maxColorDegree = new long[n];
        this.minColorDegree = new long[n];
        this.colorDegree = new HashMap<>();
        this.coloring = new HashMap<>();

        for (int i = 0; i < n; i++) {
            colorClasses.add(new ArrayList<>());
            positiveDegreeColorClasses.add(new ArrayList<>());
        }

        Map<V, Long> alphaColors = alpha.getColors();
        for (V v : graph.vertexSet()) {
            long color = alphaColors.get(v);
            colorClasses.get((int) color).add(v);
            colorDegree.put(v, 0L);
            coloring.put(v, color);
        }

        lastUsedColor = alpha.getNumberColors() - 1;
    }
}

