import java.util.Arrays;

public class EigenSolver {
    // Wrapper for LAPACK dgeev function (assumed available via JNI or similar)
    // Note: This is a stub; actual binding would require JNI or a library like Apache Commons Math or ND4J
    private static native int LAPACKE_dgeev(int matrixLayout, int jobvl, int jobvr,
                                             long n, double[] a, long lda,
                                             double[] wr, double[] wi,
                                             double[] vl, long ldvl,
                                             double[] vr, long ldvr);

    // Constants for LAPACK
    private static final int LAPACK_COL_MAJOR = 102;
    private static final int LAPACK_NO_VECTOR = 0;
    private static final int LAPACK_VECTOR = 1;

    public static class Matrix<T> {
        private final double[][] data;
        private final int rows;
        private final int cols;

        public Matrix(double[][] data) {
            this.data = data;
            this.rows = data.length;
            this.cols = data.length > 0 ? data[0].length : 0;
        }

        public boolean isSquare() {
            return rows == cols && rows > 0;
        }

        public int getCols() {
            return cols;
        }

        public Matrix<Double> copy() {
            double[][] copy = new double[rows][cols];
            for (int i = 0; i < rows; i++) {
                System.arraycopy(data[i], 0, copy[i], 0, cols);
            }
            return new Matrix<>(copy);
        }

        // For simplicity, assume ptr access is simulated via flat array and stride
        public double[] flatten() {
            double[] flat = new double[rows * cols];
            for (int i = 0; i < rows; i++) {
                System.arraycopy(data[i], 0, flat, i * cols, cols);
            }
            return flat;
        }
    }

    public static class Vector<T> {
        private final Complex64[] data;

        public Vector(Complex64[] data) {
            this.data = data;
        }

        public Complex64 get(int i) {
            return data[i];
        }

        public void set(int i, Complex64 value) {
            data[i] = value;
        }
    }

    public static class Complex64 {
        public final double real;
        public final double imag;

        public Complex64(double real, double imag) {
            this.real = real;
            this.imag = imag;
        }

        @Override
        public String toString() {
            return "(" + real + "+" + imag + "i)";
        }
    }

    public static class MatrixComplex {
        private final Complex64[][] data;
        private final int rows;
        private final int cols;

        public MatrixComplex(int rows, int cols) {
            this.rows = rows;
            this.cols = cols;
            this.data = new Complex64[rows][cols];
            for (int i = 0; i < rows; i++) {
                Arrays.fill(data[i], new Complex64(0.0, 0.0));
            }
        }

        public void set(int row, int col, Complex64 value) {
            data[row][col] = value;
        }

        public Complex64 get(int row, int col) {
            return data[row][col];
        }
    }

    public static class Result {
        public final Vector<Complex64> eigenvalues;
        public final MatrixComplex eigenvectors;

        public Result(Vector<Complex64> eigenvalues, MatrixComplex eigenvectors) {
            this.eigenvalues = eigenvalues;
            this.eigenvectors = eigenvectors;
        }
    }

    public static Result eig(Matrix<Double> a, boolean right) {
        if (!a.isSquare()) {
            throw new IllegalArgumentException("eig: input matrix must be square");
        }

        int N = a.getCols();
        double[] wr = new double[N];
        double[] wi = new double[N];
        double[] v_read = new double[N * N]; // column-major storage
        double[] v_empty = new double[N * N];
        Matrix<Double> a_copy = a.copy();
        double[] a_flat = a_copy.flatten();

        int info;
        if (right) {
            // jobvl = NO_VECTOR, jobvr = VECTOR
            info = LAPACKE_dgeev(LAPACK_COL_MAJOR, LAPACK_NO_VECTOR, LAPACK_VECTOR,
                    N, a_flat, N, wr, wi, v_empty, N, v_read, N);
        } else {
            // jobvl = VECTOR, jobvr = NO_VECTOR
            info = LAPACKE_dgeev(LAPACK_COL_MAJOR, LAPACK_VECTOR, LAPACK_NO_VECTOR,
                    N, a_flat, N, wr, wi, v_read, N, v_empty, N);
        }

        if (info != 0) {
            throw new RuntimeException("LAPACKE_dgeev failed with info = " + info);
        }

        // Build eigenvalues and eigenvectors
        Complex64[] eigvals = new Complex64[N];
        MatrixComplex eigvecs = new MatrixComplex(N, N);

        int i = 0;
        while (i < N) {
            eigvals[i] = new Complex64(wr[i], wi[i]);
            if (wi[i] > 0.0) {
                // Complex conjugate pair
                eigvals[i + 1] = new Complex64(wr[i + 1], wi[i + 1]);
                for (int j = 0; j < N; j++) {
                    // v_read is column-major: element (j, i) is at index j + i*N
                    int idx_ji = j + i * N;
                    int idx_jip1 = j + (i + 1) * N;
                    double realPart = v_read[idx_ji];
                    double imagPart = v_read[idx_jip1];
                    eigvecs.set(j, i, new Complex64(realPart, imagPart));
                    eigvecs.set(j, i + 1, new Complex64(realPart, -imagPart));
                }
                i += 2;
            } else {
                // Real eigenvalue
                for (int j = 0; j < N; j++) {
                    int idx_ji = j + i * N;
                    eigvecs.set(j, i, new Complex64(v_read[idx_ji], 0.0));
                }
                i++;
            }
        }

        return new Result(new Vector<>(eigvals), eigvecs);
    }

    // Example main method for demonstration (not part of original, but added per requirement)
    public static void main(String[] args) {
        // Example usage would go here; LAPACK binding must be initialized.
        // This is a skeleton — actual use requires proper native library setup.
    }
}

