public class HilbertMatrix {
    public static <T extends Number> double[][] hilbert(int N) {
        double[][] res = new double[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                // T.fromInt(1) / T.fromInt(i + j + 1) → 1.0 / (i + j + 1)
                res[i][j] = 1.0 / (i + j + 1);
            }
        }
        return res;
    }

    public static void main(String[] args) {
        // Example usage
        int N = 4;
        double[][] hilbertMatrix = hilbert(N);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                System.out.printf("%.6f ", hilbertMatrix[i][j]);
            }
            System.out.println();
        }
    }
}

