public static BigMoney multiply(BigMoney a, BigMoney b, String mode) {
    // 默认模式为 "round"
    if (mode == null) {
        mode = "round";
    }

    int fraction = a.getCurrency().getFraction();
    java.math.BigInteger exp = java.math.BigInteger.TEN.pow(fraction);
    java.math.BigInteger product = a.getAmount().multiply(b.getAmount());
    java.math.BigInteger res = product.divide(exp);

    if ("round".equals(mode)) {
        java.math.BigInteger remainder = product.remainder(exp);
        java.math.BigInteger halfExp = exp.divide(java.math.BigInteger.valueOf(2));

        if (product.signum() < 0) {
            // 负数：检查 -remainder < halfExp
            java.math.BigInteger negRemainder = remainder.negate();
            if (negRemainder.compareTo(halfExp) < 0) {
                return new BigMoney(res, a.getCurrency());
            } else {
                return new BigMoney(res.subtract(java.math.BigInteger.ONE), a.getCurrency());
            }
        } else {
            // 正数：检查 remainder < halfExp
            if (remainder.compareTo(halfExp) < 0) {
                return new BigMoney(res, a.getCurrency());
            } else {
                return new BigMoney(res.add(java.math.BigInteger.ONE), a.getCurrency());
            }
        }
    } else if ("truncate".equals(mode)) {
        return new BigMoney(res, a.getCurrency());
    } else if ("ceil".equals(mode)) {
        if (product.signum() == 0) {
            return new BigMoney(res, a.getCurrency());
        } else if (product.signum() < 0) {
            return new BigMoney(res.subtract(java.math.BigInteger.ONE), a.getCurrency());
        } else {
            return new BigMoney(res.add(java.math.BigInteger.ONE), a.getCurrency());
        }
    } else {
        throw new IllegalArgumentException("没有舍入模式" + mode);
    }
}

