/**
 * Asserts that two vectors are approximately equal element-wise.
 *
 * @param a the first vector
 * @param b the second vector
 * @param atol absolute tolerance threshold (default: 1e-7)
 * @param <T> numeric type that supports floating-point comparison and string conversion
 * @throws AssertionException if vectors have different sizes or any pair of elements differs beyond tolerance
 */
public static <T extends Number> void assertApproxEqual(Vector<T> a, Vector<T> b, double atol) {
    if (a.size() != b.size()) {
        throw new AssertionException("assertApproxEqual: vector dimension is not same.");
    }
    int size = a.size();
    for (int i = 0; i < size; i++) {
        assertApproxEqual(a.get(i), b.get(i), atol);
    }
}

