    // Native method declaration for C binding
    private static native long c_contour_nlevels(double[] xPtr, double[] yPtr, double[] zPtr,
                                                  int row, int col, int nLevels, long cstrLineSpec);

    // Assuming Matrix<T> is a custom matrix class with shape(), getRows(), getCols(), ptr() methods
    // and that ptr() returns a double[] for Float64 matrices.
    // Contours is a wrapper class holding a native handle (long).
    public static Contours contour(Matrix<Double> x, Matrix<Double> y, Matrix<Double> z,
                                   int nLevels, String lineSpec) {
        if (!x.shape().equals(y.shape()) || !x.shape().equals(z.shape())) {
            throw new IllegalArgumentException("contour: dimension mismatch");
        }
        int row = x.getRows();
        int col = x.getCols();

        // Convert lineSpec to C string (null-terminated byte array)
        long cstrLineSpec = mallocCString(lineSpec);

        try {
            long handle = c_contour_nlevels(
                (double[]) x.ptr(),
                (double[]) y.ptr(),
                (double[]) z.ptr(),
                row, col, nLevels, cstrLineSpec
            );
            return new Contours(handle);
        } finally {
            free(cstrLineSpec);
        }
    }

    // Overloaded version with default line_spec = ""
    public static Contours contour(Matrix<Double> x, Matrix<Double> y, Matrix<Double> z,
                                   int nLevels) {
        return contour(x, y, z, nLevels, "");
    }

    // Stub implementations for C string memory management (to be provided by JNI layer)
    private static native long mallocCString(String s);
    private static native void free(long ptr);
}

