public void setTiffMarker(int marker) {
    final int standardTiffMarker = 0x002A;
    final int olympusRawTiffMarker = 0x4F52;
    final int olympusRawTiffMarker2 = 0x5352;
    final int panasonicRawTiffMarker = 0x0055;

    if (marker == 0x002A || marker == 0x4F52 || marker == 0x5352) {
        pushDirectory(new ExifIFD0Directory());
    } else if (marker == 0x0055) {
        pushDirectory(new PanasonicRawIFD0Directory());
    } else {
        throw new TiffProcessingException("Unexpected TIFF marker: " + marker);
    }
}

