/**
 * Computes the maximum absolute difference between two symmetric band matrices
 * stored in packed format, considering only the upper or lower triangular part.
 *
 * @param uplo Specifies whether the matrices are stored in upper ('U') or lower ('L') format
 * @param n The order of the matrices
 * @param kd The number of super- or sub-diagonals
 * @param a Array containing the first symmetric band matrix in packed storage
 * @param lda Leading dimension of array a
 * @param b Array containing the second symmetric band matrix in packed storage
 * @param ldb Leading dimension of array b
 * @return The maximum absolute difference (NaN-safe)
 */
public static double distSymBand(char uplo, long n, long kd, double[] a, long lda, double[] b, long ldb) {
    double dist = 0.0;
    if (uplo == 'U' || uplo == 'u') {
        for (long i = 0; i < n; i++) {
            long limit = Math.min(kd + 1, n - i);
            for (long j = 0; j < limit; j++) {
                double diff = Math.abs(a[(int)(i * lda + j)] - b[(int)(i * ldb + j)]);
                dist = Double.isNaN(dist) ? diff : (Double.isNaN(diff) ? dist : Math.max(dist, diff));
            }
        }
    } else if (uplo == 'L' || uplo == 'l') {
        for (long i = 0; i < n; i++) {
            long start = Math.max(0L, kd - i);
            long end = kd + 1;
            for (long j = start; j < end; j++) {
                double diff = Math.abs(a[(int)(i * lda + j)] - b[(int)(i * ldb + j)]);
                dist = Double.isNaN(dist) ? diff : (Double.isNaN(diff) ? dist : Math.max(dist, diff));
            }
        }
    }
    return dist;
}

output:
func distSymBand(uplo: Uplo, n: Int64, kd: Int64, a: Array<Float64>, lda: Int64, b: Array<Float64>, ldb: Int64): Float64 {
    var dist: Float64 = 0.0
    if (uplo == Upper) {
        for (i in 0..n) {
            for (j in 0..min(kd + 1, n - i)) {
                dist = nanMax(dist, abs(a[i * lda + j] - b[i * ldb + j]))
            }
        }
    } else if (uplo == Lower) {
        for (i in 0..n) {
            for (j in max(0, kd - i)..kd + 1) {
                dist = nanMax(dist, abs(a[i * lda + j] - b[i * ldb + j]))
            }
        }
    }
    return dist
}

