public void endArray() {
    switch (peeked) {
        case PEEK_STATE_ARRAY_END:
            break;
        case PEEK_STATE_NONE:
            if (stacks.top() != JsonStateStack.JSON_ARRAY) {
                throw new IllegalStateException("Failed to end array.");
            }
            break;
        default:
            throw new IllegalStateException("The next Token is not JsonStreamEndArray.");
