private boolean compareFlush(int curflush, int oldflush) {
    if (oldflush == Z_UNKNOWN_FLUSH) {
        return false;
    }
    int curflushRank = (curflush * 2) - (curflush > Z_FINISH ? 9 : 0);
    int oldflushRank = (oldflush * 2) - (oldflush > Z_FINISH ? 9 : 0);
    return curflushRank <= oldflushRank;
}

