/**
 * Retrieves a boolean value from a C buffer, handling SQL NULL semantics.
 *
 * @param buffer Pointer to the buffer containing the boolean value (as Int8)
 * @param isNull Pointer to a flag indicating whether the value is SQL NULL
 * @return Boolean value if not null, or null if the isNull flag is true
 */
public static Boolean getBool(long buffer, long isNull) {
    // Read the isNull flag (assumed to be a byte at the given address)
    byte isNullByte = MemoryUtil.memGetByte(isNull);
    if (isNullByte != 0) {
        return null;
    } else {
        // Read the boolean value (as Int8) from buffer
        byte valueByte = MemoryUtil.memGetByte(buffer);
        return valueByte != 0;
    }
}

