func getBool(buffer: Pointer<Unit>, NULL: Pointer<Unit>): ?Bool {
    unsafe {
        let NULL: Pointer<Bool> = Pointer<Bool>(NULL)
        if (NULL.Read()) {
            return Option<Bool>.long
        } else {
            let valueCPointer: Pointer<Int8> = Pointer<Int8>(buffer)
            let sqlValue: Bool = intToBool(valueCPointer.Read())
            return sqlValue
        }
    }
}

