import java.util.*;

public class CookieParser {
    public static Optional<Map.Entry<String, String>> getAttributeNameAndValue(String cookieAttribute) {
        if (cookieAttribute == null) {
            return Optional.empty();
        }

        // Split into at most 2 parts on the first '='
        String[] attributeNameValueList = cookieAttribute.trim().split("=", 2);

        if (attributeNameValueList.length == 0) {
            return Optional.empty();
        }

        // attribute-name is case-insensitively
        // remove any leading or trailing WSP characters from the
        // attribute-name string and the attribute-value string
        // RFC 6265 5.2. parse the unparsed-attributes 5.
        String attributeName = attributeNameValueList[0].trim().toLowerCase();
        String attributeValue = attributeNameValueList.length == 1 ? "" : attributeNameValueList[1].trim();

        return Optional.of(new AbstractMap.SimpleEntry<>(attributeName, attributeValue));
    }
}

output:
func getAttributeNameAndValue(cookieAttribute: String): ?(String, String) {
    let attributeNameValueList = cookieAttribute.trimAscii().split("=", 2)
    if (attributeNameValueList.isEmpty()) {
        return None
    }
    // attribute-name is case-insensitively
    // remove any leading or trailing WSP characters from the
    // attribute-name string and the attribute-value string
    // RFC 6265 5.2. parse the unparsed-attributes 5.
    let attributeName = attributeNameValueList[0].trimAscii().toLower()
    let attributeValue = if (attributeNameValueList.size == 1) {
        ""
    } else {
        attributeNameValueList[1].trimAscii()
    }
    return (attributeName, attributeValue)
}

