public V get(Duration timeout) throws TimeoutException, CancellationException, ExecutionException {
    synchronized (lock) {
        Instant deadline = Instant.now().plus(timeout);
        while (result.isEmpty() && exception.isEmpty()) {
            Duration waitTimeRemaining = Duration.between(Instant.now(), deadline);
            if (waitTimeRemaining.toNanos() > 0) {
                futureWait(waitTimeRemaining);
            } else {
                throw new TimeoutException();
            }
        }
        if (cancelled) {
            throw new CancellationException();
        }
        return getOrThrowExecutionException();
    }
}

