private func afterNodeAccess(node: Entry<K, V>): Unit {
        var last = tail
        if (let Some(lastNode) <- last) {
            if (!refEq(lastNode, node)) {
                let b = node.prev
                let a = node.next

                node.next = node

                if (let Some(b) <- b) {
                    b.next = a
                } else {
                    head = a
                }

                if (let Some(a) <- a) {
                    a.prev = b
                } else {
                    last = b
                }
                node.prev = last
                lastNode.next = node
                tail = node
            }
        } else {
            head = node
        }
    }

