        java.util.Optional<Integer> opt = java.util.Optional.of(1);

        // if let Some(x) <- opt
        if (opt.isPresent()) {
            int x = opt.get(); // x is inferred as int (Int64 equivalent)
            System.out.println(x);
        } else {
            // if opt is None
            System.out.println("none");
        }

        // opt = None
        opt = java.util.Optional.empty();

        // if let None <- opt
        if (opt.isEmpty()) {
            System.out.println("none");
        }

        // opt = Some(1)
