import java.util.stream.Collectors;

public class ConsoleMetricExporter implements MetricExporter {

    public ConsoleMetricExporter() {}

    @Override
    public boolean export(ArrayList<MetricData> metrics) {
        System.out.println("=== Exporting Metrics ===");
        if (metrics.size() == 0) {
            System.out.println("No metrics to export");
            return true;
        }

        for (MetricData metric : metrics) {
            System.out.println("Metric: " + metric.name + " (" + metric.unit + ") - " + metric.description);
            System.out.println("  Value: " + metric.value);
            System.out.println("  Timestamp: " + metric.timestamp);
            if (metric.attributes != null && !metric.attributes.isEmpty()) {
                System.out.println("  Attributes:");
                for (Map.Entry<String, AttributeValue> entry : metric.attributes.entrySet()) {
                    System.out.println("    " + entry.getKey() + ": " + attributeValueToString(entry.getValue()));
                }
            }
        }
        return true;
    }

    @Override
    public void shutdown() {
        System.out.println("ConsoleMetricExporter shutdown");
    }

    @Override
    public void updateResourceAttributes(HashMap<String, AttributeValue> attributes) {
        // console exporter uses the payload directly and does not need extra state
    }

    private String attributeValueToString(AttributeValue value) {
        if (value instanceof AttributeValue.StringValue stringValue) {
            return stringValue.value;
        } else if (value instanceof AttributeValue.IntValue intValue) {
            return String.valueOf(intValue.value);
        } else if (value instanceof AttributeValue.DoubleValue doubleValue) {
            return String.valueOf(doubleValue.value);
        } else if (value instanceof AttributeValue.BoolValue boolValue) {
            return String.valueOf(boolValue.value);
        } else if (value instanceof AttributeValue.BytesValue bytesValue) {
            return "[" + String.join(", ", Arrays.stream(bytesValue.bytes)
                    .mapToObj(String::valueOf)
                    .collect(Collectors.toList())) + "]";
        } else if (value instanceof AttributeValue.ArrayValue arrayValue) {
            List<String> items = new ArrayList<>();
            for (AttributeValue item : arrayValue.values) {
                items.add(attributeValueToString(item));
            }
            return "[" + String.join(", ", items) + "]";
        } else if (value instanceof AttributeValue.KvList kvList) {
            List<String> entries = new ArrayList<>();
            for (Map.Entry<String, AttributeValue> entry : kvList.map.entrySet()) {
                entries.add(entry.getKey() + ": " + attributeValueToString(entry.getValue()));
            }
            return "{" + String.join(", ", entries) + "}";
        }
        return "";
    }

    private void printNumberDataPoints(ArrayList<OtlpNumberDataPoint> points) {
        for (OtlpNumberDataPoint point : points) {
            String value;
            if (point.asDouble != null) {
                value = String.valueOf(point.asDouble);
            } else if (point.asInt != null) {
                value = String.valueOf(point.asInt);
            } else {
                value = "0";
            }
            System.out.println("      Value: " + value);
            if (point.attributes != null && !point.attributes.isEmpty()) {
                System.out.println("        Attributes:");
                for (OtlpKeyValue attr : point.attributes) {
                    System.out.println("          " + attr.key + ": " + prettyPrintAnyValue(attr.value));
                }
            }
        }
    }

    private String prettyPrintAnyValue(OtlpAnyValue value) {
        if (value.stringValue != null) {
            return value.stringValue;
        } else if (value.boolValue != null) {
            return String.valueOf(value.boolValue);
        } else if (value.intValue != null) {
            return String.valueOf(value.intValue);
        } else if (value.doubleValue != null) {
            return String.valueOf(value.doubleValue);
        } else if (value.bytesValue != null) {
            return value.bytesValue;
        } else if (value.arrayValue != null) {
            List<String> items = new ArrayList<>();
            for (OtlpAnyValue item : value.arrayValue.values) {
                items.add(prettyPrintAnyValue(item));
            }
            return "[" + String.join(", ", items) + "]";
        } else if (value.kvlistValue != null) {
            List<String> entries = new ArrayList<>();
            for (OtlpKeyValue kv : value.kvlistValue.values) {
                entries.add(kv.key + ": " + prettyPrintAnyValue(kv.value));
            }
            return "{" + String.join(", ", entries) + "}";
        } else {
            return "";
        }
    }
}

