import java.io.OutputStream;
import java.util.Optional;

// Represents a block-based writer that buffers bytes and writes them in chunks.
// Uses an Encoder object to handle the actual encoding and buffering logic.
public class BlockWriter extends OutputStream {
    // The encoder responsible for buffering and writing data.
    private final Encoder e;

    /**
     * Constructor initializing the BlockWriter with an Encoder.
     *
     * @param e the Encoder to use for buffering and writing
     */
    public BlockWriter(Encoder e) {
        this.e = e;
    }

    /**
     * Initializes the buffer by setting the first byte (length counter) to 0.
     */
    public void setup() {
        this.e.buf[0] = 0;
    }

    /**
     * Flushes the underlying encoder; throws any pending error.
     *
     * @throws Exception if an error is pending in the encoder
     */
    @Override
    public void flush() throws Exception {
        if (this.e.err != null) {
            throw this.e.err;
        }
    }

    /**
     * Writes a single byte to the buffer.
     * If the buffer fills (reaches 255 data bytes), it writes the full block (256 bytes including length).
     *
     * @param c the byte to write
     * @throws Exception if an error occurred during encoding or writing
     */
    @Override
    public void write(int c) throws Exception {
        // Check for pending error before proceeding
        if (this.e.err != null) {
            throw this.e.err;
        }

        // Increment count of buffered bytes (stored at buf[0])
        this.e.buf[0]++;

        // Store byte at position corresponding to current count (1-indexed in buffer)
        this.e.buf[this.e.buf[0]] = (byte) c;

        // If buffer is full (255 data bytes, i.e., buf[0] == 255), write the block
        if (this.e.buf[0] == 255) {
            this.e.write(this.e.buf, 0, 256); // write 256-byte block: [len][data...]
            this.e.buf[0] = 0; // reset counter
        }
    }

    /**
     * Writes an array of bytes.
     * Each byte is written individually via write(int), which handles buffering and flushing.
     *
     * @param data the byte array to write
     * @throws Exception if any write operation fails
     */
    @Override
    public void write(byte[] data) throws Exception {
        for (byte b : data) {
            write(b & 0xFF); // ensure unsigned byte value
        }
    }

    /**
     * Closes the writer by writing any remaining buffered bytes,
     * followed by a final zero-length block if buffer is empty,
     * then flushing the encoder.
     *
     * @throws Exception if writing or flushing fails
     */
    @Override
    public void close() throws Exception {
        if (this.e.buf[0] == 0) {
            // Write a zero-length block: [0]
            this.e.writeByte((byte) 0);
        } else {
            // Write block with length N + terminator: [N][data...][0], total N+2 bytes
            int n = this.e.buf[0];
            this.e.buf[n + 1] = 0; // append terminator
            this.e.write(this.e.buf, 0, n + 2);
        }
        this.e.flush();
    }
}

