public class PgFloat4Converter {
    public static float pgFloat4(byte[] val, short fmtCode) {
        if (fmtCode == 0) {
            // Text format: parse from UTF-8 encoded string
            String istr = new String(val, java.nio.charset.StandardCharsets.UTF_8);
            return Float.parseFloat(istr);
        } else {
            // Binary format: interpret as big-endian IEEE 754 float32 bit pattern
            int bits = 0;
            bits |= ((val[0] & 0xFF) << 24);
            bits |= ((val[1] & 0xFF) << 16);
            bits |= ((val[2] & 0xFF) << 8);
            bits |= (val[3] & 0xFF);
            return Float.intBitsToFloat(bits);
        }
    }
}

