public MessagePacker packInt64(long value) {
    if (value < -(1L << 5)) {
        if (value < -(1L << 15)) {
            if (value < -(1L << 31)) {
                writeByteAndInt64(INT64, value);
            } else {
                writeByteAndInt32(INT32, (int) value);
            }
        } else {
            if (value < -(1L << 7)) {
                writeByteAndInt16(INT16, (short) value);
            } else {
                writeByteAndInt8(INT8, (byte) value);
            }
        }
    } else if (value < (1L << 7)) {
        writeByte((byte) value);
    } else {
        if (value < (1L << 16)) {
            if (value < (1L << 8)) {
                writeByteAndUInt8(UINT8, (byte) value);
            } else {
                writeByteAndUInt16(UINT16, (short) value);
            }
        } else {
            if (value < (1L << 32)) {
                writeByteAndUInt32(UINT32, (int) value);
            } else {
