public func deinterlace(pixels: Array<UInt8>, width: Int64): Array<UInt8> {
    var newPixels: Array<UInt8> = Array<UInt8>(pixels.size, item: 0)
    var rows: Int64 = pixels.size / width

    var quyu: Int64 = pixels.size % width
    if (quyu > 0) {
        rows += 1
    }

    func cpRow(toRow: Int64, fromRow: Int64) {
        var len: Int64 = ((fromRow + 1) * width) - (fromRow * width)
        if (len > (pixels.size - (fromRow * width))) {
            len = pixels.size - (fromRow * width)
        }

        let fromPixels: Array<UInt8> = pixels.slice(fromRow * width, len)
        fromPixels.copyTo(newPixels, 0, toRow * width, len)
    }

    var offsets: Array<Int64> = [0, 4, 2, 1]
    var steps: Array<Int64> = [8, 8, 4, 2]
    var fromRow: Int64 = 0

    for (pass in 0..4) {
        var toRow: Int64 = offsets[pass]
        while (toRow < rows) {
            // Crop the pixels array according to its width and
            // concatenate it according to special requirements [length unchanged, order changed]
            cpRow(toRow, fromRow)
            fromRow++
            toRow += steps[pass]
        }
    }

    return newPixels
}

