import java.util.Objects;

public class VectorUtils {
    public static <T extends CNumber<T>> Vector<T> apply2(Vector<T> x, Vector<T> y,
            java.util.function.BinaryOperator<T> f) {
        if (x.size() != y.size()) {
            throw new IllegalArgumentException("apply2: dimension mismatch");
        }

        int size = x.size();
        Vector<T> res = new Vector<>(size);
        for (int i = 0; i < size; i++) {
            res.set(i, f.apply(x.get(i), y.get(i)));
        }
        return res;
    }
}

output:
public func apply2<T>(x: Vector<T>, y: Vector<T>, f: (T, T) -> T): Vector<T> where T <: CNumber<T> {
    if (x.size() != y.size()) {
        throw IllegalArgumentException("apply2: dimension mismatch")
    }

    let size = x.size()
    let res = Vector<T>(size)
    for (i in 0..size) {
        res[i] = f(x[i], y[i])
    }
    return res
}

